CREATE TABLE IF NOT EXISTS supervision_wecom_config (id BIGINT PRIMARY KEY AUTO_INCREMENT,tenant_key VARCHAR(64) NOT NULL DEFAULT 'default',corp_id VARCHAR(128) NOT NULL,directory_secret_cipher TEXT NULL,agent_id INT NULL,app_secret_cipher TEXT NULL,callback_token_cipher TEXT NULL,encoding_aes_key_cipher TEXT NULL,status TINYINT NOT NULL DEFAULT 1,last_verified_at DATETIME NULL,last_sync_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uk_wecom_tenant(tenant_key));
CREATE TABLE IF NOT EXISTS supervision_department (id BIGINT PRIMARY KEY AUTO_INCREMENT,tenant_key VARCHAR(64) NOT NULL,wecom_department_id BIGINT NOT NULL,parent_wecom_department_id BIGINT NULL,name VARCHAR(128) NOT NULL,order_no INT DEFAULT 0,status TINYINT NOT NULL DEFAULT 1,synced_at DATETIME NULL,UNIQUE KEY uk_department_external(tenant_key,wecom_department_id));
CREATE TABLE IF NOT EXISTS supervision_person (id BIGINT PRIMARY KEY AUTO_INCREMENT,tenant_key VARCHAR(64) NOT NULL,wecom_user_id VARCHAR(128) NOT NULL,name VARCHAR(128) NOT NULL,mobile_masked VARCHAR(32) NULL,email VARCHAR(255) NULL,position_name VARCHAR(128) NULL,avatar_url VARCHAR(512) NULL,status TINYINT NOT NULL DEFAULT 1,synced_at DATETIME NULL,UNIQUE KEY uk_person_external(tenant_key,wecom_user_id));
CREATE TABLE IF NOT EXISTS supervision_person_department (person_id BIGINT NOT NULL,department_id BIGINT NOT NULL,is_main TINYINT NOT NULL DEFAULT 0,PRIMARY KEY(person_id,department_id));
CREATE TABLE IF NOT EXISTS supervision_org_sync_log (id BIGINT PRIMARY KEY AUTO_INCREMENT,tenant_key VARCHAR(64) NOT NULL,operator_id BIGINT NULL,status VARCHAR(32) NOT NULL,department_count INT DEFAULT 0,person_count INT DEFAULT 0,created_count INT DEFAULT 0,updated_count INT DEFAULT 0,deactivated_count INT DEFAULT 0,error_detail VARCHAR(1024) NULL,started_at DATETIME NOT NULL,ended_at DATETIME NULL);
ALTER TABLE supervision_account ADD CONSTRAINT fk_account_person FOREIGN KEY (person_id) REFERENCES supervision_person(id);